-- SurakshaNet AI MVP SQL Server schema
CREATE TABLE Roles (Id INT IDENTITY PRIMARY KEY, Name NVARCHAR(50) NOT NULL UNIQUE);
CREATE TABLE Users (Id INT IDENTITY PRIMARY KEY, FullName NVARCHAR(120) NOT NULL, Mobile NVARCHAR(30) NOT NULL, Email NVARCHAR(160) NOT NULL UNIQUE, PasswordHash NVARCHAR(256) NOT NULL, PreferredLanguage NVARCHAR(20) NOT NULL DEFAULT 'en', VerificationLevel NVARCHAR(50) NOT NULL DEFAULT 'Basic', IsActive BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE TABLE UserRoles (UserId INT NOT NULL FOREIGN KEY REFERENCES Users(Id), RoleId INT NOT NULL FOREIGN KEY REFERENCES Roles(Id), PRIMARY KEY(UserId, RoleId));
CREATE TABLE Departments (Id INT IDENTITY PRIMARY KEY, Name NVARCHAR(120) NOT NULL, DepartmentType NVARCHAR(80) NOT NULL, ContactEmail NVARCHAR(160) NULL, ContactMobile NVARCHAR(30) NULL, IsActive BIT NOT NULL DEFAULT 1);
CREATE TABLE Incidents (Id INT IDENTITY PRIMARY KEY, IncidentCode NVARCHAR(40) NOT NULL UNIQUE, Category NVARCHAR(100) NOT NULL, Title NVARCHAR(180) NOT NULL, Description NVARCHAR(MAX) NULL, Latitude DECIMAL(9,6) NOT NULL, Longitude DECIMAL(9,6) NOT NULL, LocationText NVARCHAR(240) NULL, Severity NVARCHAR(30) NOT NULL DEFAULT 'Medium', Status NVARCHAR(60) NOT NULL DEFAULT 'Submitted', VerificationStatus NVARCHAR(60) NOT NULL DEFAULT 'Pending', IsAnonymous BIT NOT NULL DEFAULT 1, ReporterUserId INT NOT NULL FOREIGN KEY REFERENCES Users(Id), AssignedDepartmentId INT NULL FOREIGN KEY REFERENCES Departments(Id), CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), UpdatedAt DATETIME2 NULL);
CREATE TABLE IncidentMedia (Id INT IDENTITY PRIMARY KEY, IncidentId INT NOT NULL FOREIGN KEY REFERENCES Incidents(Id), MediaType NVARCHAR(30) NOT NULL, FileUrl NVARCHAR(500) NOT NULL, IsRedacted BIT NOT NULL DEFAULT 1, EvidenceHash NVARCHAR(128) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE TABLE IncidentVerificationLogs (Id INT IDENTITY PRIMARY KEY, IncidentId INT NOT NULL FOREIGN KEY REFERENCES Incidents(Id), VerifiedByUserId INT NULL FOREIGN KEY REFERENCES Users(Id), VerificationType NVARCHAR(80) NOT NULL, Result NVARCHAR(80) NOT NULL, Remarks NVARCHAR(MAX) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE TABLE GeoFences (Id INT IDENTITY PRIMARY KEY, IncidentId INT NULL FOREIGN KEY REFERENCES Incidents(Id), Latitude DECIMAL(9,6) NOT NULL, Longitude DECIMAL(9,6) NOT NULL, RadiusMeters INT NOT NULL, Severity NVARCHAR(30) NOT NULL, RiskType NVARCHAR(100) NOT NULL, Status NVARCHAR(40) NOT NULL DEFAULT 'Active', ExpiresAt DATETIME2 NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), ResolvedAt DATETIME2 NULL);
CREATE TABLE Alerts (Id INT IDENTITY PRIMARY KEY, GeoFenceId INT NULL FOREIGN KEY REFERENCES GeoFences(Id), Title NVARCHAR(180) NOT NULL, Message NVARCHAR(MAX) NOT NULL, Language NVARCHAR(20) NOT NULL DEFAULT 'en', Severity NVARCHAR(30) NOT NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE TABLE PublicIssues (Id INT IDENTITY PRIMARY KEY, IncidentId INT NOT NULL FOREIGN KEY REFERENCES Incidents(Id), PublicTitle NVARCHAR(180) NOT NULL, PublicSummary NVARCHAR(MAX) NOT NULL, ReporterIdentityLabel NVARCHAR(80) NOT NULL DEFAULT 'Identity Protected', PublicStatus NVARCHAR(60) NOT NULL DEFAULT 'Published', SupportCount INT NOT NULL DEFAULT 0, IsHidden BIT NOT NULL DEFAULT 0, HideReason NVARCHAR(500) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE TABLE Solutions (Id INT IDENTITY PRIMARY KEY, IncidentId INT NOT NULL FOREIGN KEY REFERENCES Incidents(Id), SuggestedByUserId INT NOT NULL FOREIGN KEY REFERENCES Users(Id), Title NVARCHAR(180) NOT NULL, Description NVARCHAR(MAX) NOT NULL, SolutionType NVARCHAR(80) NOT NULL, VerificationStatus NVARCHAR(60) NOT NULL DEFAULT 'Pending', SupportCount INT NOT NULL DEFAULT 0, ExpertReviewStatus NVARCHAR(60) NOT NULL DEFAULT 'NotRequested', CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE TABLE Petitions (Id INT IDENTITY PRIMARY KEY, IncidentId INT NOT NULL FOREIGN KEY REFERENCES Incidents(Id), Title NVARCHAR(180) NOT NULL, Summary NVARCHAR(MAX) NOT NULL, VerificationStatus NVARCHAR(60) NOT NULL DEFAULT 'Pending', SupportCount INT NOT NULL DEFAULT 0, Status NVARCHAR(60) NOT NULL DEFAULT 'Open', CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE TABLE PetitionSupporters (Id INT IDENTITY PRIMARY KEY, PetitionId INT NOT NULL FOREIGN KEY REFERENCES Petitions(Id), UserId INT NOT NULL FOREIGN KEY REFERENCES Users(Id), IsAnonymous BIT NOT NULL DEFAULT 1, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE TABLE HelperRequests (Id INT IDENTITY PRIMARY KEY, RequestedByUserId INT NOT NULL FOREIGN KEY REFERENCES Users(Id), HelpType NVARCHAR(80) NOT NULL, Message NVARCHAR(MAX) NULL, ApproxLatitude DECIMAL(9,6) NOT NULL, ApproxLongitude DECIMAL(9,6) NOT NULL, ExactLocationShared BIT NOT NULL DEFAULT 0, AcceptedByHelperUserId INT NULL FOREIGN KEY REFERENCES Users(Id), Status NVARCHAR(60) NOT NULL DEFAULT 'Open', CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), ClosedAt DATETIME2 NULL);
CREATE TABLE AuditLogs (Id INT IDENTITY PRIMARY KEY, EntityName NVARCHAR(100) NOT NULL, EntityId INT NOT NULL, Action NVARCHAR(100) NOT NULL, PerformedByUserId INT NULL FOREIGN KEY REFERENCES Users(Id), OldValue NVARCHAR(MAX) NULL, NewValue NVARCHAR(MAX) NULL, Remarks NVARCHAR(MAX) NULL, CreatedAt DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
CREATE INDEX IX_Incidents_Status ON Incidents(Status, VerificationStatus);
CREATE INDEX IX_GeoFences_Active ON GeoFences(Status, ExpiresAt);
CREATE INDEX IX_AuditLogs_Entity ON AuditLogs(EntityName, EntityId);
